const item = $input.item.json;
const companyName = item.company_name || '';
const jobTitle = item.job_title || '';
const location = item.location || '';
const jobUrl = item.job_url || '';
const jobDescription = item.job_description || '';
const userSkills = item.user_skills || '';
const techStack = item.tech_stack || '';

const id = 'app-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);

const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const appliedDate = `${year}-${month}-${day}`;

const folderName = `${day}_${companyName.replace(/[^a-zA-Z0-9]/g, '_')}_${jobTitle.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20)}`;
const folderPath = `/home/n8n/.n8n/vault/${year}/${month}/${folderName}`;

const jobRequirements = jobDescription;

return [{
  json: {
    application_id: id,
    company_name: companyName,
    job_title: jobTitle,
    location: location,
    job_url: jobUrl,
    job_description: jobDescription,
    job_requirements: jobRequirements,
    user_skills: userSkills,
    tech_stack: techStack,
    applied_date: appliedDate,
    folder_path: folderPath,
    year: year,
    month: month,
    day: day,
    vault_path: '/home/n8n/.n8n/vault',
    folder_name: folderName
  }
}];

const jobData = $input.item.json;

async function callOllama(prompt) {
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'http://ollama:11434/api/generate',
        headers: { 'Content-Type': 'application/json' },
        body: { model: 'llama3.2', prompt: prompt, stream: false },
      });
      return (resp && resp.response) ? resp.response : '[No response]';
    } catch (e) {
      if (attempt === 3) return `[Ollama Error: ${e.message}]`;
      await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000));
    }
  }
}

const resumePrompt = `Generate a tailored resume for ${jobData.company_name} ${jobData.job_title} position. Job requirements: ${jobData.job_requirements}. User skills: ${jobData.user_skills}. Match skills exactly to requirements. Use metrics and STAR method. Format as professional resume with sections: Summary, Experience, Skills, Education. Be specific and quantifiable.`;

const coverLetterPrompt = `Write a compelling cover letter for ${jobData.company_name} ${jobData.job_title} position. Show genuine interest in the company and role. Be personal, specific, and professional. Keep to 3-4 paragraphs. Explain why you're interested in this specific company and role, not generic application letter.`;

const resume = await callOllama(resumePrompt);
const coverLetter = await callOllama(coverLetterPrompt);

const metadataContent = `# Application: ${jobData.company_name} - ${jobData.job_title}\n\n- Company: ${jobData.company_name}\n- Title: ${jobData.job_title}\n- Location: ${jobData.location}\n- URL: ${jobData.job_url}\n- Applied: ${jobData.applied_date}\n- Application ID: ${jobData.application_id}\n\n## Job Description\n${jobData.job_description}\n\n## Requirements\n${jobData.job_requirements}\n`;

const resumeContent = `# Resume - ${jobData.job_title} at ${jobData.company_name}\n\n${resume}`;
const coverLetterContent = `# Cover Letter - ${jobData.company_name}\n\n${coverLetter}`;

return [{
  json: {
    ...jobData,
    tier1_status: 'complete',
    resume_preview: resume.substring(0, 300),
    metadata_content: metadataContent,
    resume_content: resumeContent,
    cover_letter_content: coverLetterContent
  }
}];

