const jobData = $input.item.json;
const { execSync } = require('child_process');
const dbPath = '/home/n8n/.n8n/job_search.db';

function sqlExec(sql) {
  try {
    execSync(`sqlite3 ${dbPath}`, { input: sql, timeout: 10000 });
  } catch(e) {
    console.error('SQLite error:', e.message);
  }
}

function escapeSql(s) {
  return String(s || '').replace(/'/g, "''");
}

sqlExec(`CREATE TABLE IF NOT EXISTS applications (
  id TEXT PRIMARY KEY,
  company_name TEXT,
  job_title TEXT,
  location TEXT,
  job_url TEXT,
  job_description TEXT,
  applied_date TEXT,
  status TEXT DEFAULT 'applied',
  folder_path TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);`);

sqlExec(`CREATE TABLE IF NOT EXISTS tier_outputs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  application_id TEXT,
  tier_name TEXT,
  status TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);`);

sqlExec(`CREATE TABLE IF NOT EXISTS follow_ups (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  application_id TEXT,
  due_date TEXT,
  type TEXT,
  status TEXT DEFAULT 'pending',
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);`);

sqlExec(`CREATE TABLE IF NOT EXISTS analytics (
  id TEXT PRIMARY KEY,
  metric_name TEXT,
  metric_value INTEGER,
  last_updated TEXT
);`);

sqlExec(`INSERT OR REPLACE INTO applications (id, company_name, job_title, location, job_url, job_description, applied_date, status, folder_path) VALUES (
  '${escapeSql(jobData.application_id)}',
  '${escapeSql(jobData.company_name)}',
  '${escapeSql(jobData.job_title)}',
  '${escapeSql(jobData.location)}',
  '${escapeSql(jobData.job_url)}',
  '${escapeSql(jobData.job_description)}',
  '${escapeSql(jobData.applied_date)}',
  'applied',
  '${escapeSql(jobData.folder_path)}'
);`);

const tiers = ['tier1', 'tier2', 'tier3', 'tier4', 'tier5'];
for (const tier of tiers) {
  sqlExec(`INSERT INTO tier_outputs (application_id, tier_name, status) VALUES ('${escapeSql(jobData.application_id)}', '${tier}', 'complete');`);
}

const now = new Date();
const fu1Date = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const fu2Date = new Date(now.getTime() + 14 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const fu3Date = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

sqlExec(`INSERT INTO follow_ups (application_id, due_date, type) VALUES ('${escapeSql(jobData.application_id)}', '${fu1Date}', 'follow_up_1');`);
sqlExec(`INSERT INTO follow_ups (application_id, due_date, type) VALUES ('${escapeSql(jobData.application_id)}', '${fu2Date}', 'follow_up_2');`);
sqlExec(`INSERT INTO follow_ups (application_id, due_date, type) VALUES ('${escapeSql(jobData.application_id)}', '${fu3Date}', 'follow_up_3');`);

sqlExec(`INSERT OR REPLACE INTO analytics (id, metric_name, metric_value, last_updated) VALUES ('total_applications', 'total_applications', COALESCE((SELECT metric_value FROM analytics WHERE id = 'total_applications'), 0) + 1, datetime('now'));`);

let totalApplications = 1;
try {
  const result = execSync(`sqlite3 ${dbPath} 'SELECT COUNT(*) FROM applications'`, { encoding: 'utf8', timeout: 10000 });
  totalApplications = parseInt(result.trim()) || 1;
} catch(e) {
  console.error('Count query error:', e.message);
}

const trackingContent = `# Application Tracking: ${jobData.company_name} - ${jobData.job_title}\n\n## Status\n- Application ID: ${jobData.application_id}\n- Status: Applied\n- Applied Date: ${jobData.applied_date}\n\n## Follow-up Schedule\n- Follow-up 1: ${fu1Date}\n- Follow-up 2: ${fu2Date}\n- Follow-up 3: ${fu3Date}\n\n## Generated Content\n- metadata_content\n- resume_content\n- cover_letter_content\n- cold_email_content\n- company_research_content\n- personal_angle_content\n- interview_prep_content\n- portfolio_content\n\n## Links\n- Job URL: ${jobData.job_url}\n- Vault Path: ${jobData.folder_path}\n`;

const analyticsContent = `# Job Search Analytics\n\n## Overview\n- Total Applications: ${totalApplications}\n- Last Updated: ${jobData.applied_date}\n\n## Recent Application\n- Company: ${jobData.company_name}\n- Position: ${jobData.job_title}\n- Date: ${jobData.applied_date}\n`;

return [{
  json: {
    ...jobData,
    tier5_status: 'complete',
    total_applications: totalApplications,
    follow_up_1_date: fu1Date,
    follow_up_2_date: fu2Date,
    follow_up_3_date: fu3Date,
    tracking_content: trackingContent,
    analytics_content: analyticsContent
  }
}];

const jobData = $input.item.json;
const githubToken = process.env.GITHUB_TOKEN || '';

if (!githubToken) {
  console.log('Warning: GITHUB_TOKEN not set, skipping git commit');
  return [{
    json: {
      ...jobData,
      git_status: 'skipped'
    }
  }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const apiBase = 'https://api.github.com';
const headers = {
  'Authorization': `token ${githubToken}`,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: `${apiBase}${path}`,
    headers: headers,
    body: body,
  });
}

try {
  const refData = await apiRequest('GET', `/repos/${owner}/${repo}/git/refs/heads/main`);
  const currentSha = refData.object.sha;

  const commitData = await apiRequest('GET', `/repos/${owner}/${repo}/git/commits/${currentSha}`);
  const treeSha = commitData.tree.sha;

  const filesToCommit = [];

  const contentMap = {
    'metadata.md': jobData.metadata_content,
    'resume.md': jobData.resume_content,
    'cover_letter.md': jobData.cover_letter_content,
    'cold_email.md': jobData.cold_email_content,
    'company_research.md': jobData.company_research_content,
    'personal_angle.md': jobData.personal_angle_content,
    'interview_prep.md': jobData.interview_prep_content,
    'portfolio_matching.md': jobData.portfolio_content,
    'tracking.md': jobData.tracking_content
  };

  for (const [fileName, content] of Object.entries(contentMap)) {
    if (!content) {
      console.log(`Skipping ${fileName}: no content available`);
      continue;
    }
    try {
      const blobData = await apiRequest('POST', `/repos/${owner}/${repo}/git/blobs`, {
        content: Buffer.from(content).toString('base64'),
        encoding: 'base64'
      });
      const repoPath = `${jobData.year}/${jobData.month}/${jobData.folder_name}/${fileName}`;
      filesToCommit.push({ path: repoPath, mode: '100644', type: 'blob', sha: blobData.sha });
    } catch(e) {
      console.error(`Error processing file ${fileName}:`, e.message);
    }
  }

  if (jobData.analytics_content) {
    try {
      const analyticsBlobData = await apiRequest('POST', `/repos/${owner}/${repo}/git/blobs`, {
        content: Buffer.from(jobData.analytics_content).toString('base64'),
        encoding: 'base64'
      });
      filesToCommit.push({ path: 'analytics.md', mode: '100644', type: 'blob', sha: analyticsBlobData.sha });
    } catch(e) {
      console.error('Error processing analytics.md:', e.message);
    }
  }

  if (filesToCommit.length === 0) {
    return [{
      json: {
        ...jobData,
        git_status: 'skipped',
        git_note: 'No content to commit'
      }
    }];
  }

  const newTreeData = await apiRequest('POST', `/repos/${owner}/${repo}/git/trees`, {
    base_tree: treeSha,
    tree: filesToCommit
  });
  const newTreeSha = newTreeData.sha;

  const commitMessage = `Job application: ${jobData.company_name} - ${jobData.job_title} - ${jobData.applied_date}`;
  const newCommitData = await apiRequest('POST', `/repos/${owner}/${repo}/git/commits`, {
    message: commitMessage,
    tree: newTreeSha,
    parents: [currentSha],
    author: {
      name: 'Odeliya Charitonova',
      email: 'odaliya12@gmail.com',
      date: new Date().toISOString()
    }
  });
  const newCommitSha = newCommitData.sha;

  await apiRequest('PATCH', `/repos/${owner}/${repo}/git/refs/heads/main`, {
    sha: newCommitSha,
    force: false
  });

  return [{
    json: {
      ...jobData,
      git_status: 'success',
      commit_sha: newCommitSha
    }
  }];

} catch(e) {
  console.error('Git commit failed:', e.message);
  return [{
    json: {
      ...jobData,
      git_status: 'error',
      git_error: e.message
    }
  }];
}
